// Get the corrected content from incoming JSON
let corrected = items[0].json.corrected || "";

// If it's a stringified JSON block with triple backticks, clean it up
if (typeof corrected === "string") {
  corrected = corrected.trim();

  // Remove surrounding ``` if present
  if (corrected.startsWith("```") && corrected.endsWith("```")) {
    corrected = corrected.replace(/^```(?:json)?\n?/, "").replace(/```$/, "").trim();
  }

  // If it still looks like a JSON string, try parsing it and extracting "Corrected Output"
  try {
    const parsed = JSON.parse(corrected);
    if (parsed["Corrected Output"]) {
      corrected = parsed["Corrected Output"];
    }
  } catch (e) {
    // leave as-is if not parsable
  }
}

return [
  {
    json: {
      corrected
    }
  }
];

const output = $json.output || "";

// Extract values from markdown using regex
const sessionIdMatch = output.match(/\*\*Session ID:\*\*\s*([a-f0-9\-]+)/i);
const loopCounterMatch = output.match(/\*\*Loop Counter:\*\*\s*(\d+)/);
const rawQueryMatch = output.match(/\*\*RawQuery:\*\*\s*\[([\s\S]*?)\]/);
const scoreMatch = output.match(/\*\*Evaluation Score:\*\*\s*(\d+)\/10/);
const mistakesMatch = output.match(/\*\*Mistakes Found:\*\*\s*([\s\S]*?)\*\*Suggestions:/);
const suggestionsMatch = output.match(/\*\*Suggestions:\*\*\s*([\s\S]*?)\*\*Corrected Output:/);
const correctedMatch = output.match(/\*\*Corrected Output:\*\*\s*([\s\S]*)/);

// Parse and prepare values
const sessionId = sessionIdMatch ? sessionIdMatch[1].trim() : "";
const rawQuery = rawQueryMatch ? rawQueryMatch[1].trim() : "";
const currentLoopCounter = loopCounterMatch ? parseInt(loopCounterMatch[1]) : 0;
const incrementedLoopCounter = currentLoopCounter + 1;
const score = scoreMatch ? parseInt(scoreMatch[1]) : 0;

const mistakes = mistakesMatch ? mistakesMatch[1].trim() : "";
const suggestions = suggestionsMatch ? suggestionsMatch[1].trim() : "";
const corrected = correctedMatch ? correctedMatch[1].trim() : "";

return {
  json: {
    sessionId,
    rawQuery,
    loopCounter: incrementedLoopCounter,
    score,
    mistakes,
    suggestions,
    corrected
  }
};

