const sessionId = $json.sessionId || "";
const rawInput = $json.chatInput || ""; // Assuming $json.chatInput is the source of the raw text

// Initialize loopCounter (preserve if already present)
const loopCounter = $json.loopCounter ?? 0;

const scoreMatch = rawInput.match(/\*\*Evaluation Score:\*\*\s*(\d+)\/10/);
const mistakesMatch = rawInput.match(/\*\*Mistakes Found:\*\*([\s\S]*?)\*\*Suggestions:\*\*/);
const suggestionsMatch = rawInput.match(/\*\*Suggestions:\*\*([\s\S]*?)\*\*Corrected Output:\*\*/);
const correctedMatch = rawInput.match(/\*\*Corrected Output:\*\*([\s\S]*)/);

const isEvaluation = scoreMatch && correctedMatch;

// Build the inputString that combines all relevant data
let inputString = '';

if (isEvaluation) {
    inputString += `--- Evaluation Input ---\n`;
    inputString += `Original Request: ${(!isEvaluation && rawInput.trim()) || 'N/A'}\n`;
    inputString += `Raw User Input (from evaluation): ${rawInput.trim()}\n`;
    inputString += `Is Evaluation: Yes\n`;
    inputString += `Evaluation Score: ${scoreMatch ? parseInt(scoreMatch[1]) : 'N/A'}\n`;
    inputString += `Mistakes Found: ${mistakesMatch ? mistakesMatch[1].trim() : 'None'}\n`;
    inputString += `Suggestions: ${suggestionsMatch ? suggestionsMatch[1].trim() : 'None'}\n`;
    inputString += `Corrected Output: ${correctedMatch ? correctedMatch[1].trim() : 'N/A'}\n`;
    inputString += `--- End Evaluation Input ---\n\n`;
    inputString += `Based on the evaluation feedback above, please generate the next improved prompt, adhering to the system message instructions.`;
} else {
    inputString += `--- New User Input ---\n`;
    inputString += `Raw User Input: ${rawInput.trim()}\n`;
    inputString += `Is Evaluation: No\n`;
    inputString += `--- End New User Input ---\n\n`;
    inputString += `Please generate a prompt based on this input, adhering to the system message instructions.`;
}

return {
  json: {
    sessionId: sessionId,
    loopCounter: loopCounter, // ✅ Pass loop counter forward
    inputString: inputString,
    rawQuery: rawInput // ✅ Added original chat trigger input for reuse downstream
  }
};

const output = $json.output || "";

// Match sessionId from pattern: **SessionId:** [value]
const sessionIdMatch = output.match(/\*\*SessionId:\*\*\s*\[?([a-f0-9-]+)\]?/i);

// Match loopCounter from pattern: **LoopCounter:** [number]
const loopCounterMatch = output.match(/\*\*LoopCounter:\*\*\s*\[?(\d+)\]?/i);

// Match rawQuery from pattern: **RawQuery:** [text]
const rawQueryMatch = output.match(/\*\*RawQuery:\*\*\s*\[([\s\S]*?)\]/i);

// Match generated prompt — everything between [ and ] after **Output:**
const promptMatch = output.match(/\*\*Output:\*\*\s*\[([\s\S]*?)\](?:\n|$)/i);

return {
  json: {
    sessionId: sessionIdMatch ? sessionIdMatch[1].trim() : "",
    loopCounter: loopCounterMatch ? parseInt(loopCounterMatch[1]) : 0,
    rawQuery: rawQueryMatch ? rawQueryMatch[1].trim() : "",
    generatedPrompt: promptMatch ? promptMatch[1].trim() : ""
  }
};

