const sessionIdMatch = output.match(/\*\*SessionId:\*\*\s*\[?([a-f0-9-]+)\]?/i);

// Match **LoopCounter:** [value]
const loopCounterMatch = output.match(/\*\*LoopCounter:\*\*\s*\[?(\d+)\]?/i);

// Match **RawQuery:** [value]
const rawQueryMatch = output.match(/\*\*RawQuery:\*\*\s*\[([\s\S]*?)\](?:\n|$)/i);

// Match **Output:** [everything after this line]
